class Solution:
    def maxOperations(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 2:
            return 0

        # Try all possible first operations
        max_ops = 0
        for i in range(1, n):
            target = nums[0] + nums[i]
            ops = 1
            j = i + 1
            while j < n:
                if nums[j] + nums[j - 1] == target:
                    ops += 1
                    j += 2
                else:
                    break
            max_ops = max(max_ops, ops)

        return max_ops
